ValidationRule.errorConditionFormula:
AND( 
	ISPICKVAL( AAR_Missing_Features__c ,""),
	OR(
		AND( 
			ISPICKVAL(AAR_Loss_Reason__c,'Missing Feature'), 
			NOT(ISPICKVAL(AAR_Product_Features__c ,'Positive'))
		),
		OR (
          ISPICKVAL( AAR_Product_Features__c ,'Negative'), 
          ISPICKVAL( AAR_Product_Features__c ,'Neutral')
        ) 
	)
)
